import{c as s,S as a,j as e,m as l}from"./chunks/framework.DvQr6YbT.js";const c=JSON.parse('{"title":"从 URL 安装","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/install-from-url.md","filePath":"zh/sharing/install-from-url.md","lastUpdated":1783409445000}'),t={name:"zh/sharing/install-from-url.md"};function h(n,i,r,o,d,p){return a(),e("div",null,[...i[0]||(i[0]=[l('<h1 id="从-url-安装" tabindex="-1">从 URL 安装 <a class="header-anchor" href="#从-url-安装" aria-label="Permalink to “从 URL 安装”">​</a></h1><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/team/kb-bundles/releases/download/v1.2.0/pack.zip</span></span></code></pre></div><p>字节流先下载到临时文件，然后走与本地安装<strong>完全相同</strong>的管道——同样的预览、同样的 规范校验与版本门、同样的路径安全检查。远程知识包做不了任何本地包做不了的事。</p><p>在 Obsidian 里，安装对话框（Dashboard → Install bundle）的 URL 输入框接受同样的 链接。</p><h2 id="公开来源" tabindex="-1">公开来源 <a class="header-anchor" href="#公开来源" aria-label="Permalink to “公开来源”">​</a></h2><p>任何能返回 zip 字节流的 <code>https://</code> URL 都可以：公开仓库的 GitHub Release 资产、 静态文件托管、对象存储。无需任何配置，也不需要 GitHub 账号。</p><p>在可信局域网内也可以用普通 <code>http://</code>——Knowlery 会提示传输未加密；拿不准时配合 <code>--verify</code> 使用。</p><h2 id="私有-github-来源" tabindex="-1">私有 GitHub 来源 <a class="header-anchor" href="#私有-github-来源" aria-label="Permalink to “私有 GitHub 来源”">​</a></h2><p>如果 URL 指向<strong>私有</strong>仓库的 Release，匿名下载会被拒绝（GitHub 返回 404——它从不 泄露私有仓库是否存在）。Knowlery 会自动改用你自己的 <code>gh</code> CLI 登录重试，并告知你：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Anonymous fetch was refused — retrieved via your gh login instead.</span></span></code></pre></div><p>前提：你对该仓库有读权限（被邀请为 collaborator，或是组织成员），且 <code>gh</code> 已安装 并登录（<code>gh auth login</code>）。</p><p><strong>没有 <code>gh</code> 时</strong>，用浏览器——你的登录会话就是凭证：</p><ol><li>打开 Release 页面，下载 zip。</li><li><code>knowlery bundle install ~/Downloads/pack.zip</code></li></ol><h2 id="校验下载" tabindex="-1">校验下载 <a class="header-anchor" href="#校验下载" aria-label="Permalink to “校验下载”">​</a></h2><p>如果分享者在链接旁公布了 SHA-256 校验和：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verify</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sha256-3f7a…</span></span></code></pre></div><p>校验发生在<strong>任何解包动作之前</strong>，针对原始下载字节；不匹配则中止并打印两个哈希， 什么都不会被安装。<code>--verify</code> 对本地文件同样有效——适合校验经聊天工具转发的 zip。</p><h2 id="另请参阅" tabindex="-1">另请参阅 <a class="header-anchor" href="#另请参阅" aria-label="Permalink to “另请参阅”">​</a></h2><ul><li><a href="./troubleshooting">分享故障排查</a>——第一条就是&quot;同事打开链接 404&quot;。</li></ul>',19)])])}const g=s(t,[["render",h]]);export{c as __pageData,g as default};
